// dashboards/agentic-ai/eval-drift.jsonnet
local grafana = import 'grafonnet/grafana.libsonnet';
local dashboard = grafana.dashboard;
local row = grafana.row;
local timeseries = grafana.panel.timeseries;

dashboard.new(
  title='Agentic AI — Eval Drift',
  uid='agentic-eval-drift',
  tags=['agentic-ai', 'quality'],
  refresh='5m',
)
.addPanel(
  timeseries.new('Groundedness Score (7d rolling)')
  + timeseries.queryOptions.withTargets([
    {
      datasource: { type: 'prometheus' },
      expr: 'avg_over_time(agentic_groundedness_score[7d])',
      legendFormat: 'groundedness',
    },
    {
      datasource: { type: 'prometheus' },
      expr: 'agentic_groundedness_baseline',
      legendFormat: 'baseline',
    },
  ])
  + timeseries.standardOptions.withThresholds({
    mode: 'absolute',
    steps: [
      { color: 'red', value: 0 },
      { color: 'yellow', value: 0.7 },
      { color: 'green', value: 0.85 },
    ],
  }),
  gridPos={ x: 0, y: 0, w: 24, h: 8 },
)

# terraform/main.tf
terraform {
  required_providers {
    grafana = {
      source  = "grafana/grafana"
      version = "~> 3.0"
    }
  }
}

resource "grafana_dashboard" "eval_drift" {
  # Read the rendered JSON from a Jsonnet build step
  config_json = file("${path.module}/../build/eval-drift.json")
  folder      = grafana_folder.agentic_ai.id
  overwrite   = true
}

resource "grafana_folder" "agentic_ai" {
  title = "Agentic AI"
}
